  async loadSplashScreen() {
    try {
      // 用内存变量控制：冷启动时显示，切后台回来不重复显示
      const app = getApp()
      if (app._splashShownThisSession) return
      app._splashShownThisSession = true

      if (!wx.cloud || !wx.cloud.database) return
      const db = wx.cloud.database()
      const res = await Promise.race([
        db.collection('starship_splash_config').doc('current').get(),
        new Promise((resolve) => setTimeout(() => resolve(null), 3000))
      ])

      const cfg = res && res.data ? res.data : null
      if (!cfg || !cfg.enabled || !cfg.mediaUrl) return

      const mediaType = cfg.mediaType || 'image'
      const countdown = cfg.countdownSeconds || 5
      this.setData({
        splashVisible: true,
        splashConfig: { mediaType, mediaUrl: cfg.mediaUrl },
        splashCountdown: countdown
      })

      if (mediaType === 'image') {
        this._splashTimer = setInterval(() => {
          const next = this.data.splashCountdown - 1
          if (next <= 0) {
            this.closeSplash()
          } else {
            this.setData({ splashCountdown: next })
          }
        }, 1000)
      } else {
        this._splashTimer = setInterval(() => {
          const next = this.data.splashCountdown - 1
          if (next <= 0) {
            clearInterval(this._splashTimer)
            this._splashTimer = null
            this.setData({ splashCountdown: 0 })
          } else {
            this.setData({ splashCountdown: next })
          }
        }, 1000)
      }
    } catch (e) {
      // 静默失败，不影响主页加载
    }
  },

  onSplashVideoEnded() {
    this.closeSplash()
  },

  closeSplash() {
    if (this.data.splashFading) return
    if (this._splashTimer) {
      clearInterval(this._splashTimer)
      this._splashTimer = null
    }
    this.setData({ splashFading: true })
    setTimeout(() => {
      this.setData({ splashVisible: false, splashFading: false })
    }, 500)
  },

