          resolveMissionRocketImage: (imagePath, rocketName, rocketConfiguration) =>
              resolveMissionRocketImage(imagePath, rocketName, rocketConfiguration),
          fallbackImageUrl: resolveMissionRocketImage(DEFAULT_SHARE_IMAGE),
