  // ========== 发射竞猜投票 ==========
  resetVoteData() {
    this.setData(getInitialVoteState())
  },

  async loadVoteData(launchId, skipCache) {
    if (!launchId) return

    // 仅前7个即将发射的任务开放竞猜
    var missions = this.data.upcomingMissions || []
    var mIdx = -1
    for (var mi = 0; mi < missions.length; mi++) {
      if (String(missions[mi].id) === String(launchId)) { mIdx = mi; break }
    }
    // 不在前7个中（包括找不到的情况，missions为空时放行让后续逻辑处理）
    if (missions.length > 0 && (mIdx < 0 || mIdx >= 7)) {
      this.setData(getInitialVoteState())
      return null
    }

    var currentLaunchId = String(launchId)
    var now = Date.now()
    this._voteRequestMeta = this._voteRequestMeta || {}
    var voteMeta = this._voteRequestMeta[currentLaunchId] || {}

    if (voteMeta.promise) {
      return voteMeta.promise
    }

    if (shouldSkipVoteRefresh({
      launchId: currentLaunchId,
      lastLoadedAt: voteMeta.loadedAt,
      ttlMs: VOTE_REFRESH_TTL,
      skipCache,
      now
    })) {
      return voteMeta.stats || null
    }

    var request = (async () => {
      // stale-while-revalidate：先用本地旧缓存即时渲染（含本地已投选项），云端结果回来后覆盖
      if (!voteMeta.stats) {
        try {
          var staleStats = await getVoteStatsStale(launchId)
          if (staleStats && this.data.launchData && String(this.data.launchData.id || '') === currentLaunchId) {
            this.setData(buildVoteState(staleStats, staleStats.myVote || getLocalVote(launchId)))
          }
        } catch (eStale) {}
      }
      var missionInfo = null
      if (this.data.launchData && String(this.data.launchData.id || '') === currentLaunchId) {
        missionInfo = { launchTime: this.data.launchData.launchTime || '', status: this.data.launchData._detailType || '' }
      }
      var stats = await getVoteStats(launchId, skipCache, missionInfo)
      var myVote = (stats && stats.myVote) || getLocalVote(launchId)
      this._voteRequestMeta[currentLaunchId] = {
        loadedAt: Date.now(),
        stats,
        promise: null
      }
      if (!this.data.launchData || String(this.data.launchData.id || '') !== currentLaunchId) return stats
      this.setData(buildVoteState(stats, myVote))
      return stats
    })()

    this._voteRequestMeta[currentLaunchId] = {
      ...voteMeta,
      promise: request
    }

    try {
      return await request
    } finally {
      var latestMeta = this._voteRequestMeta[currentLaunchId] || {}
      if (latestMeta.promise === request) {
        this._voteRequestMeta[currentLaunchId] = {
          ...latestMeta,
          promise: null
        }
      }
    }
  },

  async onVote(e) {
    var choice = e.currentTarget.dataset.choice
    var launchId = this.data.launchData.id
    if (!launchId || !choice) return
    if (this.data.voteData && this.data.voteData.votingClosed) {
      wx.showToast({ title: '竞猜已封盘', icon: 'none' })
      return
    }
    if (this.data.myVote) {
      wx.showToast({ title: '你已经投过啦', icon: 'none' })
      return
    }
    wx.vibrateShort({ type: 'medium' })
    saveLocalVote(launchId, choice)
    var oldData = this.data.voteData || { geCount: 0, buGeCount: 0 }
    var newGe = (oldData.geCount || 0) + (choice === 'ge' ? 1 : 0)
    var newBuge = (oldData.buGeCount || 0) + (choice === 'buge' ? 1 : 0)
    var total = newGe + newBuge
    var votePatch = {
      myVote: choice,
      'voteData.geCount': newGe,
      'voteData.buGeCount': newBuge,
      voteTotal: total,
      voteGePct: Math.round(newGe / total * 100),
      voteBugePct: Math.round(newBuge / total * 100)
    }
    this.setData(votePatch)
    await castVote(launchId, choice, {
      missionName: this.data.launchData.missionName,
      rocketName: this.data.launchData.rocketName,
      launchTime: this.data.launchData.launchTime
    }).then(serverData => {
      if (serverData) {
        var sGe = serverData.geCount || 0
        var sBuge = serverData.buGeCount || 0
        var sTotal = sGe + sBuge
        this.setData({
          'voteData.geCount': sGe,
          'voteData.buGeCount': sBuge,
          voteTotal: sTotal,
          voteGePct: sTotal > 0 ? Math.round(sGe / sTotal * 100) : 50,
          voteBugePct: sTotal > 0 ? Math.round(sBuge / sTotal * 100) : 50
        })
      }
    })
  }


